// Best-effort client tagging — no filtering, every event passes through
const clientPatterns = [
  { pattern: /nielsen/i, client: 'Nielsen' },
  { pattern: /walmart|wmt\b/i, client: 'Walmart Connect' },
  { pattern: /hearst/i, client: 'Hearst' },
  { pattern: /jpmc|jp\s*morgan|chase/i, client: 'JPMC' },
  { pattern: /snap\b/i, client: 'Snap' },
  { pattern: /fox\b|tubi/i, client: 'Fox/Tubi' },
  { pattern: /sony/i, client: 'Sony' },
  { pattern: /qualcomm/i, client: 'Qualcomm' },
  { pattern: /mastercard/i, client: 'Mastercard' },
  { pattern: /doordash/i, client: 'DoorDash' },
  { pattern: /disney/i, client: 'Disney' },
  { pattern: /samba/i, client: 'Samba.TV' },
  { pattern: /zeta/i, client: 'Zeta' },
  { pattern: /home\s*depot/i, client: 'The Home Depot' },
  { pattern: /spectrum|charter/i, client: 'Spectrum/Charter' },
  { pattern: /publicis/i, client: 'Publicis (via Hearst)' },
  { pattern: /best\s*buy/i, client: 'Best Buy' },
  { pattern: /roku/i, client: 'Roku' },
  { pattern: /criteo/i, client: 'Criteo' },
  { pattern: /xumo/i, client: 'Xumo' },
  { pattern: /mediaocean/i, client: 'MediaOcean' },
  { pattern: /mek\b|kassan|michael k/i, client: '3CV Internal' }
];

const items = $input.all();
const results = [];

for (const item of items) {
  const e = item.json;
  const title = (e.summary || '').trim();
  const location = e.location || '';
  const attendees = e.attendees || [];
  const organizerEmail = (e.organizer || {}).email || '';

  // Skip cancelled events and events you declined
  if (e.status === 'cancelled') continue;
  if (e.myResponseStatus === 'declined') continue;

  // Best-effort client tag (empty if no match)
  let client = '';
  for (const cp of clientPatterns) {
    if (cp.pattern.test(title)) {
      client = cp.client;
      break;
    }
  }

  // Extract structured data
  const startDT = e.start ? (e.start.dateTime || e.start.date || '') : '';
  const endDT = e.end ? (e.end.dateTime || e.end.date || '') : '';
  const isAllDay = !e.start || !e.start.dateTime;

  let durationMinutes = '';
  if (startDT && endDT && !isAllDay) {
    const startMs = new Date(startDT).getTime();
    const endMs = new Date(endDT).getTime();
    durationMinutes = Math.round((endMs - startMs) / 60000);
  }

  let dateStr = '';
  if (startDT) {
    dateStr = new Date(startDT).toLocaleDateString('en-US', { timeZone: 'America/New_York' });
  }

  let startTimeStr = '';
  let endTimeStr = '';
  if (!isAllDay && startDT) {
    startTimeStr = new Date(startDT).toLocaleTimeString('en-US', {
      timeZone: 'America/New_York', hour: '2-digit', minute: '2-digit', hour12: true
    });
    endTimeStr = new Date(endDT).toLocaleTimeString('en-US', {
      timeZone: 'America/New_York', hour: '2-digit', minute: '2-digit', hour12: true
    });
  }

  let dayOfWeek = '';
  if (startDT) {
    dayOfWeek = new Date(startDT).toLocaleDateString('en-US', {
      timeZone: 'America/New_York', weekday: 'long'
    });
  }

  let weekNumber = '';
  if (startDT) {
    const d = new Date(startDT);
    const jan1 = new Date(d.getFullYear(), 0, 1);
    weekNumber = Math.ceil((((d - jan1) / 86400000) + jan1.getDay() + 1) / 7);
  }

  const attendeeNames = attendees
    .filter(a => (a.email || '') !== 'alex@ahbadvisors.com' && (a.email || '') !== 'abrownstein@3cventures.com')
    .map(a => a.displayName || (a.email || '').split('@')[0])
    .join(', ');

  const attendeeEmailsStr = attendees
    .filter(a => (a.email || '') !== 'alex@ahbadvisors.com' && (a.email || '') !== 'abrownstein@3cventures.com')
    .map(a => a.email)
    .join(', ');

  const myStatus = e.myResponseStatus || e.status || 'confirmed';
  const organizerName = (e.organizer || {}).displayName || organizerEmail;

  results.push({
    json: {
      'Event ID': e.id || 'no-id-' + results.length,
      'Date': dateStr,
      'Day': dayOfWeek,
      'Week': weekNumber,
      'Start Time': startTimeStr,
      'End Time': endTimeStr,
      'Duration (min)': durationMinutes,
      'Event Title': title || '(No title)',
      'Client': client,
      'Meeting Type': client ? 'Client Meeting' : '',
      'Attendees': attendeeNames,
      'Attendee Emails': attendeeEmailsStr,
      'Attendee Count': attendees.length,
      'My Response': myStatus,
      'Organizer': organizerName,
      'Location': location ? location.substring(0, 200) : '',
      'All Day': isAllDay ? 'Yes' : 'No',
      'Calendar Link': e.htmlLink || ''
    }
  });
}

results.sort((a, b) => {
  const dateA = new Date(a.json['Date']);
  const dateB = new Date(b.json['Date']);
  return dateA - dateB;
});

return results;
